"use strict";var circles=Array.from(document.querySelectorAll(".sr-progress__color"));function getLength(t){var e=t.r.baseVal.value;return 2*Math.PI*e}function showTooltip(t,e){var o=document.getElementById("tooltip");o.innerHTML=e,o.style.display="block",o.style.left=t.pageX-45+"px",o.style.top=t.pageY-35+"px"}function hideTooltip(){document.getElementById("tooltip").style.display="none"}function srFill(){circles.forEach(function(t){var e=t.dataset.persentage,o=getLength(t),s=o-e/100*o;t.style.strokeDashoffset=s})}circles.forEach(function(e){var t=getLength(e);e.style.strokeDashoffset=t,e.style.strokeDasharray="".concat(t," ").concat(t),e.addEventListener("mousemove",function(t){showTooltip(t,e.dataset.text)}),e.addEventListener("mouseout",function(){hideTooltip()})}),setTimeout(srFill,500);